#include <vector>
#include <map>
#include <algorithm>
using namespace std;

const int MOD = 1e9 + 7;

long long solve(std::vector<std::vector<long long>> points) {
    map<long long, vector<long long>> y_to_xs;
    for (const auto& point : points) {
        long long x = point[0];
        long long y = point[1];
        y_to_xs[y].push_back(x);
    }

    // Sort the x-coordinates for each y
    for (auto& entry : y_to_xs) {
        sort(entry.second.begin(), entry.second.end());
    }

    // Precompute the count of pairs for each y
    map<long long, long long> y_to_pair_count;
    for (const auto& entry : y_to_xs) {
        long long y = entry.first;
        const vector<long long>& xs = entry.second;
        long long n = xs.size();
        if (n >= 2) {
            y_to_pair_count[y] = n * (n - 1) / 2;
        }
    }

    // Now, for each pair of y's, the number of trapezoids is C(m,2) * C(k,2)
    vector<long long> ys;
    for (const auto& entry : y_to_pair_count) {
        ys.push_back(entry.first);
    }

    long long total = 0;
    long long m = ys.size();
    for (int i = 0; i < m; ++i) {
        for (int j = i + 1; j < m; ++j) {
            long long y1 = ys[i];
            long long y2 = ys[j];
            long long cnt1 = y_to_pair_count[y1];
            long long cnt2 = y_to_pair_count[y2];
            total = (total + cnt1 * cnt2) % MOD;
        }
    }

    return total;
}
